    AbstractByCashComponent.prototype.onfilterType = function (idType) {
        var _this = this;
        this.filterCollection = [];
        var _idType = idType;
        this.collection.forEach(function (element) {
            if (_idType == element.utsavatype) {
                _this.filterCollection.push(element);
                //console.log(element);
            }
        });
        this.filterCollection.sort(function (a, b) { return (a.utsavaMurthyNumber > b.utsavaMurthyNumber) ? 1 : ((b.utsavaMurthyNumber > a.utsavaMurthyNumber) ? -1 : 0); });
        //console.log(_idType);
        this.countTotal(this.filterCollection, _idType);
        this.getRange(this.filterCollection, _idType);
    };
    AbstractByCashComponent.prototype.onfilterTypeBooking = function (idType) {
        var _this = this;
        this.filterCollectionBooking = [];
        var _idType = idType;
        this.collectionBooking.forEach(function (element) {
            if (element.bookingFor == "seva") {
                if (_idType == element.sevaType._id) {
                    _this.filterCollectionBooking.push(element);
                    // console.log(element);
                }
            }
            else if (element.bookingFor == "darshan") {
                if (_idType == element.darshanType._id) {
                    _this.filterCollectionBooking.push(element);
                    // console.log(element);
                }
            }
        });
        this.filterCollectionBooking.sort(function (a, b) { return (a.bookingNumber > b.bookingNumber) ? 1 : ((b.bookingNumber > a.bookingNumber) ? -1 : 0); });
        //console.log(_idType);
        this.countTotal(this.filterCollectionBooking, _idType);
        this.getRange(this.filterCollectionBooking, _idType);
    };
