module.exports = "<!-- App Title and Breadcrump -->\n<div class=\"app-title\">\n  <div>\n    <h1><i class=\"fa fa-book\"></i> Report</h1>\n  </div>\n  <ul class=\"app-breadcrumb breadcrumb\">\n    <li class=\"breadcrumb-item\">\n      <i class=\"fa fa-home fa-lg\"></i>\n    </li>\n    <li class=\"breadcrumb-item\">\n      <a routerLink=\"/admin/dashboard\">Dashboard</a>\n    </li>\n  </ul>\n</div>\n\n<!-- Body Section -->\n<div class=\"tile mb-4\">\n  <div class=\"page-header\">\n    <div class=\"row\">\n      <div class=\"col-lg-12\">\n        <h5 class=\"mb-3 line-head\" id=\"buttons\">Booking Report</h5>\n      </div>\n    </div>\n  </div>\n  <div class=\"row\">\n<br>\n    <div class=\"col-12\" style=\"border:solid;margin-bottom:35px;margin-top:15px;padding-top:15px;\">\n        <div class=\"center\">\n          <h3 class=\"\"><span> <img style=\"float:left\" width=\"20%\" src=\"../../../../../assets/img/logo.jpg\"></span>\n            <div class=\"column-header-right\" style=\"text-align: center;font-size:24px;\">\n              ಕರ್ನಾಟಕ <img width=\"8%\" src=\"../../../../../assets/img/favicon.png\">\n              ಸರ್ಕಾರ\n              <br>\n              ಹಿಂದೂ ಧಾರ್ಮಿಕ ಸಂಸ್ಥೆಗಳು ಮತ್ತು ಧರ್ಮಾದಾಯ ದತ್ತಿಗಳ ಇಲಾಖೆ <br> <br>\n              <p style=\"font-size:18px;\">ಶ್ರೀ ಕಬ್ಬಾಳಮ್ಮ ದೇವಸ್ಥಾನ,               \n                ಕಬ್ಬಾಳು ಗ್ರಾಮ, ಕನಕಪುರ ತಾಲ್ಲೂಕು, ರಾಮನಗರ ಜಿಲ್ಲೆ</p>                \n            </div>\n          </h3>\n      </div>\n    </div>\n    <br>\n    <div class=\"col-12\">\n      <form class=\"form-horizontal\" [formGroup]=\"reportForm\" (ngSubmit)=\"onSubmitForm()\">\n\n\n        <div class=\"form-group row\">\n          <!-- Start Date -->\n          <label for=\"\" class=\"control-label col-2\">Start Date</label>\n          <div class=\"col-4\">\n            <input type=\"date\" formControlName=\"startDate\" name=\"sDate\" id=\"sDate\" class=\"form-control\">\n          </div>\n          <!-- End Date -->\n          <label for=\"\" class=\"control-label col-2\">End Date</label>\n          <div class=\"col-4\">\n            <input type=\"date\" formControlName=\"endDate\" name=\"eDate\" id=\"eDate\" class=\"form-control\">\n          </div>\n        </div>\n\n        <div class=\"form-group btn-container\">\n          <hr>\n          <select (change)=\"onfilterType($event)\" style=\"padding:10px;\" class=\"control-label float-left\">\n            <option value=\"all\">All</option>\n            <option value=\"5cd0480cf6d33c5b6cefdee7\" >ವಿಶೇಷ ದರ್ಶನ</option>            \n            <option value=\"5b7a8577fb43ba07d43922c4\" >ತಡೆ ಸೇವೆ</option>\n            <option value=\"5ca5ba3e9efd5c2a009f600e\" >ಮುಡಿ ಸೇವೆ</option>\n            <option value=\"5cab548b9efd5c2a009f6057\" >ಯಂತ್ರ ಸೇವೆ</option>\n            <option value=\"5cab54c79efd5c2a009f6058\" >ತೆಂಗಿನಕಾಯಿ ಸೇವೆ</option>\n            <option value=\"5ca5b9949efd5c2a009f600c\" >ದ್ವಿಚಕ್ರ ವಾಹನ ಸೇವೆ</option>\n            <option value=\"5d4c313c2ad63f3864e0cbd8\" >ನಾಲ್ಕು ಚಕ್ರ ವಾಹನ ಸೇವೆ</option>\n            <option value=\"5d4c318a2ad63f3864e0cbd9\" >ಲಾರಿ ಬಸ್ ವಾಹನ ಸೇವೆ</option>\n          </select>\n\n          <button class=\"btn btn-primary float-right\" [disabled]=\"reportForm.invalid\">\n            <i class=\"fa fa-search fa-lg fa-fw\"></i>Search\n          </button>\n\n        </div>\n      </form>\n    </div>\n    <br>\n\n    <div class=\"col-12\" style=\"padding-top: 10px;\">\n\n      <table class=\"table table-striped table-bordered\">\n        <thead>\n          <tr>\n            <th scope=\"col\" class=\"tbc-w-5\">#</th>\n            <th scope=\"col\" class=\"tbc-w-5\">\n                ಕ್ರಮ ಸಂಖ್ಯೆ\n              </th>        \n            <th scope=\"col\" class=\"tbc-w-10\">\n              ರಸೀದಿ ನಂ.\n            </th>\n            <th scope=\"col\" class=\"tbc-w-10\">\n              ದಿನಾಂಕ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-10\">\n              ಸೇವೆಯ ದಿನಾಂಕ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-15\">\n              ಸೇವೆಯ ವಿವರ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-10\">\n              ಪಾವತಿಯ ಸ್ಥಳ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-10\">\n              ಸಂಧಾಯದ ರೀತಿ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-5\">\n              ಭಕ್ತರ ಸಂಖ್ಯೆ\n            </th>\n            <th scope=\"col\" class=\"tbc-w-10\">\n              ಮೊತ್ತ Rs.\n            </th>\n\n          </tr>\n        </thead>\n        <tbody>\n          <tr *ngFor=\"let item of filterCollection; let i=index;\">\n            <th scope=\"row\">{{ i + 1 }}</th>\n            <td>{{ (\"00000000\" + item.bookingNumber).slice(-9)}}</td>\n            <td>{{item.bookingId + (\"00000000\" + item.bookingNumber).slice(-9)}}</td>\n            <td>{{ item.bookingDate | date : 'dd-MM-yyyy'}}</td>\n            <td>{{ item.entryDate | date : 'dd-MM-yyyy'}}</td>\n            <td>\n              \n              <b>{{item.bookingFor === 'darshan'? item.darshanType?.title : item.sevaType?.title }} - Rs.{{item.bookingFor === 'darshan'? item.darshanType?.price : item.sevaType?.price }}</b>\n            </td>\n            <td>{{item.bookingBy === 'temple'? 'ಟಿ-ಕೌಂಟರ್' : 'ಟಿ-ಕೌಂಟರ್' }}</td>\n            <td>{{ item.paymentType }}</td>\n            <td>{{ item.numberOfDevotees }}</td>\n            <td>{{ item.bookingAmount }}</td>\n          </tr>\n        </tbody>\n      </table>\n      <div align=\"right\" class=\"col-12\">\n        <h3>Total ₹ {{ totalAmount }}</h3>\n      </div>\n\n      <!--\n      <nx-pagination [totalItems]=\"page.totalItems\" [itemPerPage]=\"page.itemPerPage\" [currentPage]=\"page.currentPage\" [displayPageCount]=\"page.displayPageCount\"\n        (onPageChanged)=\"onSelectPage($event)\" (onPrevious)=\"onPreviousClick()\" (onNext)=\"onNextClick()\" (onSelectItemPerPage)=\"onSelectItemPerPage($event)\">\n      </nx-pagination> -->\n    </div>\n\n  </div>\n</div>"

