module.exports = "<div class=\"modal-header\">\n  <h4 class=\"modal-title\" id=\"modal-basic-title\">Utsava Murthy Booking Details</h4>\n  <button type=\"button\" class=\"close\" aria-label=\"Close\" (click)=\"closeModal()\">\n    <span aria-hidden=\"true\">&times;</span>\n  </button>\n</div>\n\n<div class=\"modal-body\">\n\n  <form>\n\n    <div style=\"margin-bottom:25px;width:100%\">\n      <img *ngFor=\"let img of modelData.imageUrl\" width=\"100px\" [src]=\"img\" alt=\"\">&nbsp;&nbsp;\n    </div>\n    <div class=\"form-group row\">\n      <label class=\"col-sm-2 col-form-label\">Id</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.utsavaMurthyId + (\"00000000\" + modelData.utsavaMurthyNumber).slice(-9)}}</b>\n        </label>\n      </div>\n\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Trans. Id</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.transactionId}}</b>\n        </label>\n      </div>\n    </div>\n\n\n\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Devotee Name</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.devoteeName}}</b>\n        </label>\n      </div>\n\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Devotee Phone</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.devoteePhone}}</b>\n        </label>\n      </div>\n    </div>\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Devotee Address</label>\n      <div class=\"col-8\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.devoteeAddress}}</b>\n        </label>\n      </div>\n    </div>\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Start Date</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.startDate | date: 'dd-MM-yyyy'}}</b>\n        </label>\n      </div>\n\n      <label for=\"\" class=\"col-sm-2 col-form-label\">End Date</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.endDate | date: 'dd-MM-yyyy'}}</b>\n        </label>\n      </div>\n    </div>\n\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\">ID Proof Type</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.idProofType}}</b>\n        </label>\n      </div>\n      <label for=\"\" class=\"col-sm-2 col-form-label\">ID Proof No.</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.idProofNo}}</b>\n        </label>\n      </div>\n\n    </div>\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\"> Price</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{'Rs.' +  modelData.amountPaid}}</b>\n        </label>\n      </div>\n      <label for=\"\" class=\"col-sm-2 col-form-label\"> No. Of Days</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{ modelData.noOfDays}}</b>\n        </label>\n      </div>\n    </div>\n\n    <div class=\"form-group row\">\n      <label for=\"\" class=\"col-sm-2 col-form-label\">Ticker Master Name</label>\n      <div class=\"col-4\">\n        <label class=\"col-form-label\">\n          <b>: {{modelData.bookingPersonName}}</b>\n        </label>\n      </div>\n    </div>\n\n\n  </form>\n\n  <button (click)=\"printKanike()\" class=\"btn btn-warning btn-block\" style=\"padding:15px\">\n    PRINT DOCUMENT</button>\n\n</div>\n\n\n\n<!-- NEW PRINTING START *ngIf=\"!printTicket\"  -->\n<div id='printarea' class=\" solid\"\n  [ngStyle]=\"{background: 'url(../../../../assets/img/back-logo.jpg)', 'background-color':'#ffffff','background-position': 'center center', 'background-size': '20%', 'background-repeat': 'no-repeat'}\">\n  <div class=\"row\" style=\"margin-top:15px\">\n    <div class=\"column-header-left\" style=\"text-align: center;\">\n      <img style=\"padding-left:15px\" width=\"75%\" src=\"../../../../assets/img/logo.jpg\">\n      <br>\n      <div style=\"padding-left:15px\">\n        <ngx-barcode6 [bc-format]=\"'CODE128'\"\n          [bc-value]=\"modelData.utsavaMurthyId + ('00000000' + modelData.utsavaMurthyNumber).slice(-9)\" [bc-display-value]=\"true\"\n          [bc-font-size]=\"'18'\" [bc-width]=\"'1'\" [bc-height]=\"'25'\">\n        </ngx-barcode6>\n      </div>\n    </div>\n    <div class=\"column-header-middle\" style=\"text-align: center;font-size:12px;\">\n      <b style=\"font-size:14px;\">ಕರ್ನಾಟಕ <img width=\"5%\" src=\"../../../../../assets/img/favicon.png\"> ಸರ್ಕಾರ</b>\n      <br>\n      ಹಿಂದೂ ಧಾರ್ಮಿಕ ಸಂಸ್ಥೆಗಳು ಮತ್ತು ಧರ್ಮಾದಾಯ ದತ್ತಿಗಳ ಇಲಾಖೆ <br>\n      <b style=\"font-size:12px;\">ಶ್ರೀ ಕಬ್ಬಾಳಮ್ಮ ದೇವಸ್ಥಾನ\n        <br>\n        ಕಬ್ಬಾಳು ಗ್ರಾಮ, ಕನಕಪುರ ತಾಲ್ಲೂಕು, ರಾಮನಗರ ಜಿಲ್ಲೆ\n      </b>\n    </div>\n  </div>\n  <div class=\"row-receipt\">\n\n    <div class=\"column-receipt-middle\" style=\"font-size:12px;\">\n      <b style=\"font-size:18px\"> ಕಾಣಿಕೆ ರಸೀದಿ - {{modelData.utsavatype}} </b>\n    </div>\n\n  </div>\n\n  <div class=\"row-details\">\n    <div class=\"column-details-left\" style=\"font-size:12px;\">\n      <br>\n      ರಸೀದಿ ನಂ: <span\n        style=\"font-size:16px\">{{modelData.utsavaMurthyId + (\"00000000\" + modelData.utsavaMurthyNumber).slice(-9)}}</span>\n      ______________________________________________________________________\n      <br>\n      ಶ್ರೀಮತಿ/ಶ್ರೀ: {{modelData.devoteeName}}\n      <br>\n      ವಿಳಾಸ: {{modelData.devoteeAddress}}\n      <br>\n      ದೂರವಾಣಿ ಸಂಖ್ಯೆ: {{modelData.devoteePhone}}\n      ______________________________________________________________________\n      <br>\n      ಐಡಿ ಪುರಾವೆ ಮಾದರಿ: {{modelData.idProofType}}\n      <br>\n      ಐಡಿ ಪುರಾವೆ ಸಂಖ್ಯೆ: {{modelData.idProofNo}}\n      ______________________________________________________________________\n      <br>\n      ಪ್ರಾರಂಭ ದಿನಾಂಕ: {{modelData.startDate | date: 'dd-MM-yyyy'}}\n      <br>\n      ಅಂತಿಮ ದಿನಾಂಕ: {{modelData.endDate | date: 'dd-MM-yyyy'}}\n      ______________________________________________________________________\n      <br>\n      ವಿಗ್ರಹ : {{modelData.utsavatype}}\n      <br>\n      Rs. {{modelData.amountPaid}}\n\n\n      <p style=\"font-size:14px;\">\n        <br>\n\n\n        <b style=\"font-size:14px; padding:2px;padding-right:10px;\">\n          ದಾನಿಗಳ ಸಹಿ\n        </b>\n        <br>\n\n        <i class=\"fa fa-globe\"></i> ವೆಬ್ಸೈಟ್: www.kabbalamma.org</p>\n    </div>\n    <div class=\"column-details-right\" style=\"font-size:16px;\">\n      <br>\n      ದಿನಾಂಕ : {{modelData.createdAt | date: 'dd-MM-yyyy'}}\n      <br>\n      <img *ngIf=\"modelData.utsavatype == 'ಉತ್ಸವ ಮೂರ್ತಿ'\" class=\"solid\" style=\"padding:5px\" width=\"200px\" height=\"250px\" src=\"../../../../../assets/img/u-murthy.jpg\">\n      <img *ngIf=\"modelData.utsavatype == 'ಕೈ ಮೂರ್ತಿ'\" class=\"solid\" style=\"padding:5px\" width=\"200px\" height=\"250px\" src=\"../../../../../assets/img/k-murthy.jpg\">\n      <br>\n      <br><br>\n      \n      <b style=\"font-size:18px; padding:2px;padding-right:10px;\"> ಕಾರ್ಯ ನಿರ್ವಾಹಕ ಅಧಿಕಾರಿಗಳ ಪರವಾಗಿ</b>\n      <br><br>\n    </div>\n    <div class=\"row-footer\">\n      <div class=\"col-12\" style=\"font-size:10px;text-align: center;\">\n       <b>\n          ವಿಶೇಷ ಸೂಚನೆ ಶ್ರೀ ಕಬ್ಬಾಳಮ್ಮ ದೇವಿಯ ಭಕ್ತಾದಿಗಳು ದೇವಸ್ಥಾನಕ್ಕೆ ನೀಡುವಂತಹ ನಗದ್ದು ನಾಣ್ಯ ಹಾಗು ಯಾವುದೇ ಇನ್ನಿತರ ವಸ್ತುಗಳನ್ನು\n          ಆಡಳಿತ ಕಚೇರಿಗೆ ನೀಡಿ ಸೂಕ್ತ ರಸೀದಿ ಪಡಿಯತಕದ್ಧು.\n       </b>\n      </div>\n   \n    </div>\n  </div>\n\n\n</div>\n<!-- NEW PRINTING END-->"

